INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-23e15ae5-moex-00340', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「毒品上癮者的家屬，如果花了大半的精力滿足上癮者的需要或處理他留 下的爛攤子，以至於好像掉進永無休止的陷阱裡，和上癮者的關係似乎達 到『失控的狀態』，那麼就可能是『上癮加工者』或者和上癮者產生『相 互依賴』的關係。他的狀況嚴重影響到你，這樣的關係不但無法讓你所愛 的人戒癮，反而會讓你憂鬱、躁鬱、失眠，甚至精神分裂。」根據上文， 下列敘述正確的是：', '["上癮者需在家屬的掌控之下才是安全的", "家屬必須改變態度，讓上癮者自己承擔責任", "家屬即使受到嚴重不良影響，也應該多關愛上癮者", "為了上癮者的名聲，家屬宜為他隱瞞毒品上癮一事"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00341', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「回顧人類文明發展，新科學、新技術總會在不破不立的因果關係鏈中， 引發社會陣痛。……先進科技的出現，或許是『造物主』的善意，或是人 類集體意識的英明決策，一面把人類從舊的產業格局和繁重勞作中解放出 來，一面如鞭策或督促一般，迫使人類做出種種變革。比如AI，它一面釋 放出巨大的生產力，免除人類繼續從事繁冗工作之苦，一面又在用可能出 現的失業問題提醒人類：你應該往前走了！」根據上文，下列選項何者正確？', '["人類文明總是依循著優勝劣汰的法則進化", "科技發展的方向取決於決策者的意識形態", "新技術帶來失業率攀升，是科技發展的危機", "人類須運用智慧創新變革，避免被機器取代"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00342', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「她於是有了更多正當性可以待在菜園。其實，阿草從來不愛農作，在鄉 下種菜，主要是逃離愛發脾氣的阿嬤，讓阿草尋得一個喘息的空間，不必 受到阿嬤無時無刻的監看。阿嬤雖能生活自理，但見不得下人閒著沒事， 如今阿草種了菜，不但生活花費少了，子女還在收成時期更頻繁返家，明 顯是雇主獲利得多。種植最終成為勞雇關係間的平衡點，阿草從中獲得實 質的成就感，及部分脫逃的自在空間。『那個土真好，那個陽光和雨水， 真是好好種。』阿草說，相較於北寧農地的乾瘠、雨量不可掌握，高雄的 沃土簡直有不勞而獲的錯覺。」下列選項，何者不是「阿草」當時的人生 經驗？', '["人不親土親", "天助自助者", "無心插柳柳成蔭", "虎落平陽被犬欺"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00343', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「在這清淨的水中，臺灣特有種的蓋斑鬥魚時時從水草間浮起，吐著小泡 沫來營造牠的愛巢。牠那斑斕的體色以及飄逸多姿的長鰭，能使最沒有美 感的人也著迷。幾隻黃黑相間的蝶蜓，在青蔥的池岸禾草間追逐嬉戲、飛 飛停停，纖細的豆娘在臺灣萍蓬草的黃花間悠閒地緩緩飛行，偶爾一隻鮮 豔的孔雀蛺蝶，低低掠過水面，飛投對岸。這些小小的生物，使這一方小 池子變得生動活潑起來。」根據上文，下列何者最切近文中描述的狀態？', '["生意盎然", "大音希聲", "沉魚落雁", "兔走烏飛"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00344', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「哈里．杜魯門首次參加競選並一舉成功，成了美國總統。有記者去採訪 杜魯門的母親，問她：『你肯定為你的兒子感到自豪。』 她說：『不錯， 我為我兒子哈里感到自豪。但是，我也為另一個兒子自豪，他現在正在地 裡挖馬鈴薯。』」上文的主旨是：', '["媒體採訪應具有道德素養", "政治與農業有著相通共性", "母親眼中的自豪，是孩子各自努力，各有成就", "即使是同胞兄弟，後天的努力仍影響發展結果"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00345', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「我們總是輕忽失敗的經驗，失敗是個衝擊，但它的特殊力量讓我們更了 解自己。逆境其實可能是你一生中最好的經歷。」下列選項，何者與題旨 最接近？', '["滿招損，謙受益", "不以一眚掩大德", "三折肱，知為良醫", "吾生也有涯，而知也無涯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00346', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '有關公文的撰擬，下列選項錯誤的是：', '["公文寫作切忌主觀、偏見", "公文文字應簡淺明確，並加具標點符號", "為達到目的，公文語氣要謙卑，文詞要有彈性", "機關內部各單位撰擬文稿，文字用語、結構格式應力求一致"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00347', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '下列選項所使用的期望及目的語，何者不恰當？', '["教育部體育署行文教育部／請查照", "經濟部水利署行文經濟部／請核備", "財政部行文財政部臺北國稅局／希照辦", "內政部警政署行文內政部消防署／請惠允見復"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00348', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '下列關於公文的敘述正確的是：', '["內政部對行政院報告時用「呈」", "市民與臺北市政府間之申請與答復時用「函」", "總統與立法院、考試院公文往復時使用「咨」", "上級機關對所屬下級機關有所指示、交辦、批復時用「令」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00349', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '內政部行文考試院，所使用的稱謂語，正確的是：', '["貴院", "大院", "鈞院", "臺院"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL)
